        ## EXEMPLES

        Message: "Mes tickets ouverts"
        SQL: SELECT DISTINCT t.id, t.code, t.summary FROM ticket t WHERE t.creator_id = 5 AND t.status = 'Ouvert' AND t.type != 'Group'

        Message: "Les tickets assignés à moi"
        SQL: SELECT DISTINCT t.id, t.code, t.summary FROM ticket t WHERE t.assignee_id = 5 AND t.type != 'Group'

        Message: "Mes tickets créés cette semaine"
